import{_ as e,o as a,c as r,ag as d}from"./chunks/framework.DGzMGr_a.js";const x=JSON.parse('{"title":"快速入门","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1782656069000}'),l={name:"guide/getting-started.md"};function n(s,t,i,o,h,g){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="快速入门" tabindex="-1">快速入门 <a class="header-anchor" href="#快速入门" aria-label="Permalink to &quot;快速入门&quot;">​</a></h1><p>欢迎开始品质工程师技能学习之旅！本文档将帮助你做好学习前的准备，并提供一份四周速成计划。</p><hr><h2 id="📋-需要什么基础" tabindex="-1">📋 需要什么基础 <a class="header-anchor" href="#📋-需要什么基础" aria-label="Permalink to &quot;📋 需要什么基础&quot;">​</a></h2><p>学习本平台内容，建议具备以下基础：</p><table tabindex="0"><thead><tr><th>基础要求</th><th>说明</th></tr></thead><tbody><tr><td><strong>基础数学</strong></td><td>高中及以上数学水平，理解平均数、百分比等基本概念</td></tr><tr><td><strong>办公软件</strong></td><td>会使用 Excel 进行基本数据整理和图表制作</td></tr><tr><td><strong>行业背景</strong></td><td>有制造业或质量管理相关工作经验更佳（非必需）</td></tr><tr><td><strong>学习态度</strong></td><td>保持好奇心和耐心，质量工程需要严谨思维</td></tr></tbody></table><blockquote><p>如果你的数学基础较薄弱，建议先学习 <strong><a href="/guide/prerequisites">预备知识</a></strong> 中的统计学概念。</p></blockquote><hr><h2 id="🔧-学习工具准备" tabindex="-1">🔧 学习工具准备 <a class="header-anchor" href="#🔧-学习工具准备" aria-label="Permalink to &quot;🔧 学习工具准备&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">工具</th><th>用途</th><th style="text-align:center;">推荐</th></tr></thead><tbody><tr><td style="text-align:center;">📊 <strong>Excel / Google Sheets</strong></td><td>数据整理、图表绘制、SPC 模拟</td><td style="text-align:center;">Google Sheets（免费）</td></tr><tr><td style="text-align:center;">📝 <strong>Minitab</strong></td><td>专业统计分析、SPC、MSA 计算</td><td style="text-align:center;">试用版可用</td></tr><tr><td style="text-align:center;">📖 <strong>PDF 阅读器</strong></td><td>阅读标准文档（ISO 9001 等）</td><td style="text-align:center;">任意阅读器</td></tr><tr><td style="text-align:center;">🎥 <strong>笔记工具</strong></td><td>记录学习笔记和公式</td><td style="text-align:center;">Notion / Obsidian / 语雀</td></tr></tbody></table><hr><h2 id="📅-四周学习计划建议" tabindex="-1">📅 四周学习计划建议 <a class="header-anchor" href="#📅-四周学习计划建议" aria-label="Permalink to &quot;📅 四周学习计划建议&quot;">​</a></h2><h3 id="第-1-周-质量工程入门" tabindex="-1">第 1 周：质量工程入门 <a class="header-anchor" href="#第-1-周-质量工程入门" aria-label="Permalink to &quot;第 1 周：质量工程入门&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">天数</th><th>学习内容</th><th style="text-align:center;">参考链接</th></tr></thead><tbody><tr><td style="text-align:center;">第 1-2 天</td><td>质量工程概述、质量管理发展史</td><td style="text-align:center;"><a href="/basic/">基础入门</a></td></tr><tr><td style="text-align:center;">第 3-5 天</td><td>QC 七大手法（检查表、层别法、柏拉图）</td><td style="text-align:center;"><a href="/tools/">质量工具</a></td></tr><tr><td style="text-align:center;">第 6-7 天</td><td>复习 + 制作 QC 手法笔记</td><td style="text-align:center;">—</td></tr></tbody></table><h3 id="第-2-周-统计基础与-spc" tabindex="-1">第 2 周：统计基础与 SPC <a class="header-anchor" href="#第-2-周-统计基础与-spc" aria-label="Permalink to &quot;第 2 周：统计基础与 SPC&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">天数</th><th>学习内容</th><th style="text-align:center;">参考链接</th></tr></thead><tbody><tr><td style="text-align:center;">第 1-2 天</td><td>统计学基础（均值、标准差、正态分布）</td><td style="text-align:center;"><a href="/guide/prerequisites">预备知识</a></td></tr><tr><td style="text-align:center;">第 3-5 天</td><td>SPC 原理与控制图解读</td><td style="text-align:center;"><a href="/tools/spc">SPC 教程</a></td></tr><tr><td style="text-align:center;">第 6-7 天</td><td>用 Excel 练习绘制控制图</td><td style="text-align:center;">—</td></tr></tbody></table><h3 id="第-3-周-fmea-与-msa" tabindex="-1">第 3 周：FMEA 与 MSA <a class="header-anchor" href="#第-3-周-fmea-与-msa" aria-label="Permalink to &quot;第 3 周：FMEA 与 MSA&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">天数</th><th>学习内容</th><th style="text-align:center;">参考链接</th></tr></thead><tbody><tr><td style="text-align:center;">第 1-3 天</td><td>FMEA 失效模式分析（DFMEA / PFMEA）</td><td style="text-align:center;"><a href="/tools/fmea">FMEA 教程</a></td></tr><tr><td style="text-align:center;">第 4-5 天</td><td>MSA 测量系统分析（GRR 等）</td><td style="text-align:center;"><a href="/tools/msa">MSA 教程</a></td></tr><tr><td style="text-align:center;">第 6-7 天</td><td>案例练习：填写 FMEA 表格</td><td style="text-align:center;">—</td></tr></tbody></table><h3 id="第-4-周-体系标准与综合实践" tabindex="-1">第 4 周：体系标准与综合实践 <a class="header-anchor" href="#第-4-周-体系标准与综合实践" aria-label="Permalink to &quot;第 4 周：体系标准与综合实践&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">天数</th><th>学习内容</th><th style="text-align:center;">参考链接</th></tr></thead><tbody><tr><td style="text-align:center;">第 1-3 天</td><td>ISO 9001 质量管理体系核心条款</td><td style="text-align:center;"><a href="/standards/">ISO 9001</a></td></tr><tr><td style="text-align:center;">第 4-5 天</td><td>PPAP 与 8D 报告入门</td><td style="text-align:center;"><a href="/tools/ppap">PPAP</a> / <a href="/tools/8d-report">8D</a></td></tr><tr><td style="text-align:center;">第 6-7 天</td><td>完成一个综合质量改进案例</td><td style="text-align:center;">—</td></tr></tbody></table><hr><h2 id="🔗-常用资源链接" tabindex="-1">🔗 常用资源链接 <a class="header-anchor" href="#🔗-常用资源链接" aria-label="Permalink to &quot;🔗 常用资源链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">资源</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">国际标准化组织（ISO）</td><td style="text-align:left;"><a href="https://www.iso.org" target="_blank" rel="noreferrer">https://www.iso.org</a></td></tr><tr><td style="text-align:left;">ASQ 美国质量学会</td><td style="text-align:left;"><a href="https://asq.org" target="_blank" rel="noreferrer">https://asq.org</a></td></tr><tr><td style="text-align:left;">AIAG 汽车工业行动组</td><td style="text-align:left;"><a href="https://www.aiag.org" target="_blank" rel="noreferrer">https://www.aiag.org</a></td></tr><tr><td style="text-align:left;">中国质量协会</td><td style="text-align:left;"><a href="https://www.caq.org.cn" target="_blank" rel="noreferrer">https://www.caq.org.cn</a></td></tr><tr><td style="text-align:left;">Minitab 官网</td><td style="text-align:left;"><a href="https://www.minitab.com" target="_blank" rel="noreferrer">https://www.minitab.com</a></td></tr><tr><td style="text-align:left;">NIST 工程统计手册</td><td style="text-align:left;"><a href="https://www.itl.nist.gov/div898/handbook/" target="_blank" rel="noreferrer">https://www.itl.nist.gov/div898/handbook/</a></td></tr></tbody></table><hr><blockquote><p><strong>下一站</strong>：如果你需要复习统计和质量管理基础知识，请前往 <strong><a href="/guide/prerequisites">预备知识</a></strong>。</p></blockquote>',25)])])}const b=e(l,[["render",n]]);export{x as __pageData,b as default};
